#include <gtk/gtk.h>
static void activate(GtkApplication* app, gpointer user_data) {
    GtkWidget *window = gtk_application_window_new(app);
    gtk_window_set_title(GTK_WINDOW(window), "C GTK GUI");
    gtk_window_set_default_size(GTK_WINDOW(window), 300, 200);
    GtkWidget *label = gtk_label_new("Hello from C GTK GUI!");
    gtk_container_add(GTK_CONTAINER(window), label);
    gtk_widget_show_all(window);
}
int main(int argc, char **argv) {
    GtkApplication *app = gtk_application_new("org.gtk.example", G_APPLICATION_DEFAULT_FLAGS);
    g_signal_connect(app, "activate", G_CALLBACK(activate), NULL);
    int status = g_application_run(G_APPLICATION(app), argc, argv);
    g_object_unref(app);
    return status;
}

#include <stdio.h>
#include <string.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
int main(void) {
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    struct sockaddr_in address;
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(8080);
    bind(server_fd, (struct sockaddr*)&address, sizeof(address));
    listen(server_fd, 3);
    printf("Serving on port 8080...\n");
    while (1) {
        int client_fd = accept(server_fd, NULL, NULL);
        const char *response = "HTTP/1.1 200 OK\r\nContent-Length: 23\r\nContent-Type: text/plain\r\n\r\nHello from C Web Server!";
        write(client_fd, response, strlen(response));
        close(client_fd);
    }
    return 0;
}

#include <stdio.h>
#include <sqlite3.h>
int main(void) {
    sqlite3 *db;
    sqlite3_open(":memory:", &db);
    sqlite3_exec(db, "CREATE TABLE users(name TEXT);", NULL, NULL, NULL);
    sqlite3_exec(db, "INSERT INTO users VALUES('Alice');", NULL, NULL, NULL);
    sqlite3_close(db);
    printf("C Database connection successful.\n");
    return 0;
}
